Value.Calculation:
Let (
[
    stateValue = JSONGetElement ( $state ; "currentDate" )
] ;
    Case (
        not IsEmpty ( stateValue ) and Left ( stateValue ; 1 ) ≠ "?" ;
        stateValue ;
        Settings_Get ( "layouts.184.currentDate" ; date.format ( Get ( CurrentDate ) ; "yyyy-mm-dd" ) )
    )
)

Let (
[
    stateValue = JSONGetElement ( $state ; "currentView" )
] ;
    Case (
        not IsEmpty ( stateValue ) and Left ( stateValue ; 1 ) ≠ "?" ;
        stateValue ;
        Settings_Get ( "layouts.184.currentView" ; "weekly" )
    )
)

Let (
[
    stateValue = JSONGetElement ( $state ; "displayType" )
] ;
    Case (
        not IsEmpty ( stateValue ) and Left ( stateValue ; 1 ) ≠ "?" ;
        stateValue ;
        Settings_Get ( "layouts.184.displayType" ; "timeline" )
    )
)

JSONSetElement ( "{}" ;
    [ "currentDate" ; $currentDate ; JSONString ] ;
    [ "currentView" ; $currentView ; JSONString ] ;
    [ "displayType" ; $displayType ; JSONString ] ;
    [ "workingDays" ; JSONGetElement ( $layoutSettings ; "workingDays" ) ; JSONString ] ;
    [ "workStartHour" ; JSONGetElement ( $layoutSettings ; "workStartHour" ) ; JSONString ] ;
    [ "workEndHour" ; JSONGetElement ( $layoutSettings ; "workEndHour" ) ; JSONString ]
)
